          '19': { text: 'Όταν κάποιος σας κριτικάρει, πιο συχνά:', options: ['Το παίρνετε πολύ σοβαρά — τα πρότυπα και η ακεραιότητά σας είναι βαθιά σημαντικά', 'Νιώθετε πληγωμένοι — θέλετε να σας θεωρούν καλούς και φροντιστικούς', 'Υπερασπίζεστε την εικόνα σας — η κριτική στη δουλειά σας γίνεται προσωπική', 'Αναλύετε ορθολογικά το σχόλιο αλλά αποσύρεστε για να το επεξεργαστείτε μόνοι'] },
          '20': { text: 'Η πιο πολύτιμη προσωπική σας ποιότητα:', options: ['Η ακεραιότητά σας και η δέσμευσή σας στο σωστό', 'Η καρδιά σας — η ικανότητά σας να αγαπάτε και να προσφέρετε', 'Η δύναμη κινητοποίησής σας και η ικανότητα να μετατρέπετε φιλοδοξίες σε πραγματικότητα', 'Η νοημοσύνη σας και το βάθος κατανόησης'] },
          '21': { text: 'Ποιος είναι ο βαθύτερος σκοπός σας στη ζωή;', options: ['Να είστε αγαθοί, να βελτιώνετε τα πράγματα και να αφήσετε τον κόσμο καλύτερο', 'Να αγαπάτε και να αγαπιέστε — να είστε σημαντικοί για τους άλλους', 'Να πετυχαίνετε, να αφήνετε σημάδι και να εμπνέετε θαυμασμό', 'Να κατανοείτε — να γνωρίζετε την αλήθεια στο βαθύτερο επίπεδο'] },
          '22': { text: 'Όταν αισθάνεστε μια σύγκρουση να πλησιάζει:', options: ['Νιώθετε την ανάγκη να διορθώσετε αυτό που είναι λάθος ή άδικο', 'Εστιάζετε στο να εξομαλύνετε τα πράγματα και να αποκαταστήσετε τη ζεστασιά', 'Τη λύνετε γρήγορα και στρατηγικά για να προχωρήσετε', 'Παρατηρείτε από απόσταση και προτιμάτε να μην εμπλακείτε'] },
          '23': { text: 'Ποια παιδική εμπειρία θα μπορούσε να σας ταιριάζει;', options: ['Σας επαινούσαν για «καλή συμπεριφορά» και σας επέκριναν για λάθη', 'Νιώθατε ότι η αγάπη έπρεπε να κερδηθεί με το να είστε χρήσιμοι', 'Σας εκτιμούσαν περισσότερο όταν διακρίνεστε ή εντυπωσιάζατε', 'Προτιμούσατε τον προσωπικό σας χώρο από τις κοινωνικές απαιτήσεις'] },
          '24': { text: 'Πώς μοιάζει μια «καλή ζωή» για εσάς;', options: ['Ζωή ακεραιότητας, σκοπού και γνήσιου θετικού αντίκτυπου', 'Ζωή γεμάτη βαθιές, αγαπητικές, ουσιαστικές σχέσεις', 'Ζωή επιτευγμάτων, αναγνώρισης και μακροχρόνιας επιτυχίας', 'Ζωή γνώσης, κατανόησης και πνευματικής ελευθερίας'] },
          '25': { text: 'Όταν αισθάνεστε αβέβαιοι, αναζητάτε πρώτα:', options: ['Σαφείς κανόνες και ηθικές αρχές για να σας καθοδηγήσουν', 'Διαβεβαίωση από τους αγαπημένους σας', 'Ένα πλάνο δράσης που σας δίνει αίσθηση ελέγχου', 'Χρόνο μόνοι για να αναλύσετε την κατάσταση'] },
